  const {cashDom, listener, resolvers, sendEvent, util, CartInteractionName, CatalogObjectInteractionName, OrderInteractionName} = SalesforceInteractions;
  const currentURL = new URL(window.location.href);
  const parseText = value => {
    if (value == null) return null;
    try {
      const str = String(value).trim();
      SalesforceInteractions.log.debug("String conversion:", value, "→", str);
      if (str === "") return null;
      return str;
    } catch (error) {
      SalesforceInteractions.log.error("Type conversion parsing failed:", error);
      SalesforceInteractions.log.error("String conversion failed:", error);
      return null;
    }
  };
  const parseNumber = value => {
    if (value == null || value === "") return null;
    try {
      const parsed = Number(String(value).trim());
      return isNaN(parsed) ? null : parsed;
    } catch (error) {
      SalesforceInteractions.log.error("Type conversion parsing failed:", error);
      return null;
    }
  };
